import React, { useState } from 'react';
import { supabase } from '../services/supabaseClient';
import { useNavigate, Link } from 'react-router-dom';
import { Wallet, Mail, Lock, User, ArrowRight, AlertCircle, CheckCircle2 } from 'lucide-react';

const Registro = () => {
  const [formData, setFormData] = useState({ nome: '', email: '', password: '', confirmPassword: '' });
  const [loading, setLoading] = useState(false);
  const [status, setStatus] = useState({ type: null, message: '' });
  const navigate = useNavigate();

  const handleRegister = async (e) => {
    e.preventDefault();
    setLoading(true);
    setStatus({ type: null, message: '' });

    // Validação básica de senha
    if (formData.password !== formData.confirmPassword) {
      setStatus({ type: 'error', message: 'As senhas não coincidem.' });
      setLoading(false);
      return;
    }

    const { data, error } = await supabase.auth.signUp({
      email: formData.email,
      password: formData.password,
      options: {
        // ESSA PARTE ENVIA O NOME PARA A TRIGGER NO BANCO
        data: {
          nome: formData.nome,
        },
      },
    });

    if (error) {
      setStatus({ type: 'error', message: error.message });
      setLoading(false);
    } else {
      setStatus({ 
        type: 'success', 
        message: 'Conta criada com sucesso! Redirecionando...' 
      });
      // Pequeno delay para o usuário ler a mensagem de sucesso
      setTimeout(() => navigate('/'), 2000);
    }
  };

  const theme = {
    primary: '#4361ee',
    dark: '#0f172a',
    bg: '#f8fafc',
    surface: '#ffffff'
  };

  return (
    <div style={{ 
      minHeight: '100vh', 
      display: 'flex', 
      alignItems: 'center', 
      justifyContent: 'center', 
      backgroundColor: theme.bg,
      padding: '20px'
    }}>
      <div className="fade-in" style={{ 
        width: '100%', 
        maxWidth: '450px', 
        backgroundColor: theme.surface, 
        padding: '40px', 
        borderRadius: '32px',
        boxShadow: '0 20px 25px -5px rgba(0,0,0,0.05)'
      }}>
        
        <div style={{ textAlign: 'center', marginBottom: '30px' }}>
          <div style={{ 
            background: 'linear-gradient(135deg, #4361ee, #4cc9f0)', 
            width: '50px', height: '50px', borderRadius: '15px', 
            display: 'flex', alignItems: 'center', justifyContent: 'center',
            margin: '0 auto 15px auto'
          }}>
            <Wallet color="white" size={28} />
          </div>
          <h1 style={{ fontSize: '1.6rem', fontWeight: 800, color: theme.dark, margin: 0 }}>Crie sua conta</h1>
          <p style={{ color: '#64748b', fontSize: '0.9rem', marginTop: '5px' }}>Comece a organizar suas finanças hoje.</p>
        </div>

        {/* MENSAGENS DE FEEDBACK */}
        {status.message && (
          <div style={{ 
            backgroundColor: status.type === 'error' ? '#fef2f2' : '#f0fdf4', 
            color: status.type === 'error' ? '#b91c1c' : '#166534', 
            padding: '12px', borderRadius: '12px', fontSize: '0.85rem', 
            display: 'flex', alignItems: 'center', gap: '10px', marginBottom: '20px',
            border: `1px solid ${status.type === 'error' ? '#fee2e2' : '#dcfce7'}`
          }}>
            {status.type === 'error' ? <AlertCircle size={18} /> : <CheckCircle2 size={18} />}
            {status.message}
          </div>
        )}

        <form onSubmit={handleRegister} style={{ display: 'flex', flexDirection: 'column', gap: '18px' }}>
          <div>
            <label style={labelStyle}>Nome Completo</label>
            <div style={inputWrapperStyle}>
              <User size={18} color="#94a3b8" />
              <input 
                type="text" required placeholder="Ex: João Silva"
                style={inputStyle}
                onChange={(e) => setFormData({...formData, nome: e.target.value})}
              />
            </div>
          </div>

          <div>
            <label style={labelStyle}>E-mail</label>
            <div style={inputWrapperStyle}>
              <Mail size={18} color="#94a3b8" />
              <input 
                type="email" required placeholder="seu@email.com"
                style={inputStyle}
                onChange={(e) => setFormData({...formData, email: e.target.value})}
              />
            </div>
          </div>

          <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '15px' }}>
            <div>
              <label style={labelStyle}>Senha</label>
              <div style={inputWrapperStyle}>
                <Lock size={18} color="#94a3b8" />
                <input 
                  type="password" required placeholder="••••"
                  style={inputStyle}
                  onChange={(e) => setFormData({...formData, password: e.target.value})}
                />
              </div>
            </div>
            <div>
              <label style={labelStyle}>Confirmar</label>
              <div style={inputWrapperStyle}>
                <Lock size={18} color="#94a3b8" />
                <input 
                  type="password" required placeholder="••••"
                  style={inputStyle}
                  onChange={(e) => setFormData({...formData, confirmPassword: e.target.value})}
                />
              </div>
            </div>
          </div>

          <button 
            type="submit" 
            disabled={loading}
            style={{ 
              backgroundColor: theme.primary, color: 'white', padding: '16px', 
              borderRadius: '16px', border: 'none', fontSize: '1rem', fontWeight: 700, 
              cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center',
              gap: '10px', marginTop: '10px', boxShadow: `0 10px 20px ${theme.primary}33`
            }}
          >
            {loading ? 'Processando...' : <>Criar Conta <ArrowRight size={20} /></>}
          </button>
        </form>

        <div style={{ textAlign: 'center', marginTop: '25px', fontSize: '0.9rem', color: '#64748b' }}>
          Já tem uma conta? <Link to="/login" style={{ color: theme.primary, fontWeight: 700, textDecoration: 'none' }}>Fazer Login</Link>
        </div>
      </div>
    </div>
  );
};

// Reutilizando os mesmos estilos do Login para consistência
const labelStyle = { display: 'block', fontSize: '0.75rem', fontWeight: 700, color: '#475569', marginBottom: '6px', textTransform: 'uppercase' };
const inputWrapperStyle = { display: 'flex', alignItems: 'center', gap: '10px', backgroundColor: '#f1f5f9', padding: '0 14px', borderRadius: '14px', height: '50px' };
const inputStyle = { flex: 1, background: 'none', border: 'none', outline: 'none', fontSize: '0.95rem', color: '#0f172a' };

export default Registro;
